import { Link } from 'react-router-dom';
import { ArrowRight, Layers, Zap, Brain, Target, Eye, Code2, Rocket, Shield, Users } from 'lucide-react';
import { useEffect, useRef, useState } from 'react';

/* ══════════════════════════════════════════════
   SCROLL PROGRESS HOOK
══════════════════════════════════════════════ */
function useScrollProg(ref) {
  const [p, setP] = useState(0);
  useEffect(() => {
    const fn = () => {
      if (!ref.current) return;
      const r = ref.current.getBoundingClientRect();
      setP(Math.min(1, Math.max(0, -r.top / (r.height - window.innerHeight))));
    };
    window.addEventListener('scroll', fn, { passive: true });
    fn();
    return () => window.removeEventListener('scroll', fn);
  }, []);
  return p;
}

/* ══════════════════════════════════════════════
   REVEAL WRAPPER
══════════════════════════════════════════════ */
function Reveal({ children, delay = 0, dir = 'up', style = {} }) {
  const ref = useRef(null);
  const [vis, setVis] = useState(false);
  useEffect(() => {
    const io = new IntersectionObserver(([e]) => { if (e.isIntersecting) setVis(true); }, { threshold: 0.1 });
    if (ref.current) io.observe(ref.current);
    return () => io.disconnect();
  }, []);
  const origins = { up: 'translateY(44px)', left: 'translateX(-44px)', right: 'translateX(44px)', scale: 'scale(0.88)' };
  return (
    <div ref={ref} style={{
      opacity: vis ? 1 : 0,
      transform: vis ? 'none' : (origins[dir] || origins.up),
      transition: `opacity 0.8s cubic-bezier(0.16,1,0.3,1) ${delay}s, transform 0.8s cubic-bezier(0.16,1,0.3,1) ${delay}s`,
      ...style,
    }}>{children}</div>
  );
}

/* ══════════════════════════════════════════════
   WORD REVEAL
══════════════════════════════════════════════ */
function WordReveal({ text, style = {}, accent = '' }) {
  const ref = useRef(null);
  const [vis, setVis] = useState(false);
  useEffect(() => {
    const io = new IntersectionObserver(([e]) => { if (e.isIntersecting) setVis(true); }, { threshold: 0.2 });
    if (ref.current) io.observe(ref.current);
    return () => io.disconnect();
  }, []);
  return (
    <div ref={ref} style={style}>
      {text.split(' ').map((w, i) => (
        <span key={i} style={{
          display: 'inline-block', marginRight: '0.26em',
          fontStyle: accent && w === accent ? 'italic' : 'normal',
          color: accent && w === accent ? '#5aa8ff' : 'inherit',
          opacity: vis ? 1 : 0,
          transform: vis ? 'none' : 'translateY(70%) rotate(2deg)',
          transition: `opacity 0.7s cubic-bezier(0.16,1,0.3,1) ${i * 0.08}s, transform 0.7s cubic-bezier(0.16,1,0.3,1) ${i * 0.08}s`,
        }}>{w}</span>
      ))}
    </div>
  );
}

/* ══════════════════════════════════════════════
   3D TILT
══════════════════════════════════════════════ */
function Tilt({ children, style = {} }) {
  const ref = useRef(null);
  return (
    <div ref={ref} style={{ transition: 'transform 0.18s ease', ...style }}
      onMouseMove={e => {
        const r = ref.current.getBoundingClientRect();
        const x = (e.clientX - r.left) / r.width - 0.5;
        const y = (e.clientY - r.top) / r.height - 0.5;
        ref.current.style.transform = `perspective(900px) rotateY(${x * 14}deg) rotateX(${-y * 9}deg) scale(1.03)`;
      }}
      onMouseLeave={() => { ref.current.style.transform = ''; }}
    >{children}</div>
  );
}

/* ══════════════════════════════════════════════
   CANVAS GRID BACKGROUND
══════════════════════════════════════════════ */
function GridCanvas({ color = 'rgba(0,87,255,0.06)' }) {
  const ref = useRef(null);
  useEffect(() => {
    const c = ref.current, ctx = c.getContext('2d');
    const draw = () => {
      c.width = c.offsetWidth; c.height = c.offsetHeight;
      ctx.clearRect(0, 0, c.width, c.height);
      const step = 48;
      ctx.strokeStyle = color; ctx.lineWidth = 0.7;
      for (let x = 0; x < c.width; x += step) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, c.height); ctx.stroke(); }
      for (let y = 0; y < c.height; y += step) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(c.width, y); ctx.stroke(); }
    };
    draw();
    window.addEventListener('resize', draw);
    return () => window.removeEventListener('resize', draw);
  }, [color]);
  return <canvas ref={ref} style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', pointerEvents: 'none' }} />;
}

/* ══════════════════════════════════════════════
   ANIMATED COUNTER
══════════════════════════════════════════════ */
function Counter({ end, suffix = '' }) {
  const [v, setV] = useState(0); const ref = useRef(null); const started = useRef(false);
  useEffect(() => {
    const io = new IntersectionObserver(([e]) => {
      if (e.isIntersecting && !started.current) {
        started.current = true; let c = 0; const step = end / 70;
        const t = setInterval(() => { c += step; if (c >= end) { setV(end); clearInterval(t); } else setV(Math.floor(c)); }, 18);
      }
    }, { threshold: 0.4 });
    if (ref.current) io.observe(ref.current);
    return () => io.disconnect();
  }, [end]);
  return <span ref={ref}>{v}{suffix}</span>;
}

/* ══════════════════════════════════════════════
   DATA
══════════════════════════════════════════════ */
const VALUES = [
  { Icon: Layers, title: 'Synergy',      desc: 'People, ideas, and technology working as one — creating solutions stronger than any single part.',      color: '#0057ff', colorRgb: '0,87,255'    },
  { Icon: Zap,    title: 'Innovation',   desc: 'Constantly exploring new ideas and technologies to build better, more impactful software for tomorrow.', color: '#7c3aed', colorRgb: '124,58,237' },
  { Icon: Brain,  title: 'Intelligence', desc: 'Data, insight, and strategic thinking baked into every decision — from architecture to final pixel.',     color: '#db2777', colorRgb: '219,39,119' },
];

const PHIL = [
  { n: '01', Icon: Target,  title: 'Understand First',    body: 'Great software starts with great understanding. We invest deeply in knowing your business, users, and goals before a line of code is written.' },
  { n: '02', Icon: Code2,   title: 'Agile Architecture',  body: 'Agile iteration with solid architecture — shipping working software fast while building on a foundation that scales without technical debt.' },
  { n: '03', Icon: Rocket,  title: 'Modern Technology',   body: 'AI-driven automation, cloud-native architectures, CI/CD pipelines, and advanced analytics power everything we build and ship.' },
  { n: '04', Icon: Shield,  title: 'Ship with Confidence',body: 'Build with purpose, test relentlessly, ship with confidence. Every release is production-ready and battle-tested from day one.' },
];

const STATS = [
  { end: 50,  suf: '+', label: 'Projects Delivered' },
  { end: 3,   suf: '+', label: 'Years Active'        },
  { end: 15,  suf: '+', label: 'Technologies'        },
  { end: 100, suf: '%', label: 'Satisfaction Rate'   },
];

/* ══════════════════════════════════════════════
   STICKY HERO
══════════════════════════════════════════════ */
function StickyHero() {
  const wrapRef = useRef(null);
  const prog = useScrollProg(wrapRef);

  const imgScale   = 1.2 - prog * 0.18;
  const imgSat     = 0.5 + prog * 0.6;
  const overlayOp  = 0.88 - prog * 0.38;
  const textY      = prog * -80;
  const textOp     = 1 - prog * 1.6;
  const lineW      = prog * 100;
  const glowScale  = 1 + prog * 1.2;

  return (
    <div ref={wrapRef} style={{ height: '260vh', position: 'relative' }}>
      <section style={{ position: 'sticky', top: 0, height: '100vh', overflow: 'hidden', background: '#040b18', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>

        {/* Parallax bg */}
        <img src="https://images.unsplash.com/photo-1497366216548-37526070297c?w=1800&q=80" alt="" aria-hidden
          style={{ position: 'absolute', inset: 0, width: '100%', height: '120%', objectFit: 'cover', opacity: 0.18, transform: `scale(${imgScale})`, filter: `saturate(${imgSat})`, willChange: 'transform', transition: 'none' }} />

        {/* Grid texture */}
        <GridCanvas color="rgba(0,87,255,0.04)" />

        {/* Gradient overlay dissolves on scroll */}
        <div style={{ position: 'absolute', inset: 0, background: `rgba(4,11,24,${overlayOp})`, transition: 'none' }} />
        <div style={{ position: 'absolute', inset: 0, background: 'linear-gradient(135deg, rgba(0,87,255,0.07) 0%, transparent 60%)' }} />

        {/* Expanding glow orb */}
        <div style={{ position: 'absolute', top: '45%', left: '50%', transform: `translate(-50%,-50%) scale(${glowScale})`, width: 600, height: 600, borderRadius: '50%', background: 'radial-gradient(circle, rgba(0,87,255,0.1) 0%, transparent 70%)', pointerEvents: 'none', transition: 'none' }} />

        {/* Horizontal accent line that draws on scroll */}
        <div style={{ position: 'absolute', bottom: 100, left: '50%', transform: 'translateX(-50%)', height: 1, width: `${lineW}%`, maxWidth: 500, background: 'linear-gradient(to right, transparent, rgba(0,87,255,0.8), transparent)', transition: 'none' }} />

        {/* Content — rises and fades */}
        <div className="wrap" style={{ position: 'relative', zIndex: 1, textAlign: 'center', display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '0 20px', transform: `translateY(${textY}px)`, opacity: textOp, willChange: 'transform, opacity', transition: 'none' }}>

          {/* Badge */}
          <div style={{ display: 'inline-flex', alignItems: 'center', gap: 8, padding: '7px 20px', background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: 999, fontSize: '0.75rem', fontWeight: 600, color: 'rgba(255,255,255,0.65)', marginBottom: 36, backdropFilter: 'blur(8px)', animation: 'aIn 0.9s cubic-bezier(0.16,1,0.3,1) both' }}>
            <span style={{ width: 6, height: 6, borderRadius: '50%', background: '#4ade80', boxShadow: '0 0 8px #4ade80', display: 'inline-block' }} />
            About Synnoviq
          </div>

          {/* Headline — words stagger in */}
          <h1 style={{ fontFamily: 'var(--serif)', fontSize: 'clamp(3rem,8vw,6rem)', fontWeight: 900, color: '#fff', lineHeight: 1.04, letterSpacing: '-0.035em', marginBottom: 28, maxWidth: 860 }}>
            {['Driven', 'by', 'Code.'].map((w, i) => (
              <span key={i} style={{ display: 'inline-block', marginRight: '0.22em', animation: `wIn 0.85s cubic-bezier(0.16,1,0.3,1) ${0.1 + i * 0.1}s both` }}>{w}</span>
            ))}
            <br />
            <em style={{ fontStyle: 'italic', color: '#5aa8ff' }}>
              {['Defined', 'by', 'Innovation.'].map((w, i) => (
                <span key={i} style={{ display: 'inline-block', marginRight: '0.22em', animation: `wIn 0.85s cubic-bezier(0.16,1,0.3,1) ${0.4 + i * 0.1}s both` }}>{w}</span>
              ))}
            </em>
          </h1>

