/* ══════════════════════════════════════════════
   PHILOSOPHY — sticky horizontal timeline
══════════════════════════════════════════════ */
function PhilosophySection() {
  const wrapRef = useRef(null);
  const prog = useScrollProg(wrapRef);
  const activeIdx = Math.min(PHIL.length - 1, Math.floor(prog * PHIL.length));

  // Image parallax
  const imgRef = useRef(null);
  useEffect(() => {
    const onScroll = () => {
      if (!imgRef.current || !wrapRef.current) return;
      const r = wrapRef.current.getBoundingClientRect();
      const p = Math.max(0, Math.min(1, -r.top / (r.height - window.innerHeight)));
      imgRef.current.style.transform = `scale(1.12) translateY(${p * 50}px)`;
    };
    window.addEventListener('scroll', onScroll, { passive: true });
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  return (
    <div ref={wrapRef} style={{ height: `${100 + PHIL.length * 90}vh`, position: 'relative', background: 'var(--white)' }}>
      <div style={{ position: 'sticky', top: 0, height: '100vh', overflow: 'hidden', display: 'flex', alignItems: 'center', borderTop: '1px solid var(--rule)' }}>
        <div className="wrap" style={{ width: '100%' }}>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr', gap: 48 }} className="phil-grid">

            {/* Left: image with floating overlay */}
            <div style={{ position: 'relative', borderRadius: 22, overflow: 'hidden', minHeight: 320 }} className="phil-img">
              <img ref={imgRef} src="https://images.unsplash.com/photo-1504384308090-c894fdcc538d?w=900&q=85" alt="Workspace"
                style={{ width: '100%', height: '120%', objectFit: 'cover', transformOrigin: 'center', willChange: 'transform', transition: 'none' }} />
              <div style={{ position: 'absolute', inset: 0, background: 'linear-gradient(to bottom, transparent 40%, rgba(4,11,24,0.75))' }} />
              {/* Active step badge on image */}
              <div style={{ position: 'absolute', bottom: 24, left: 24, right: 24, background: 'rgba(255,255,255,0.12)', backdropFilter: 'blur(16px)', border: '1px solid rgba(255,255,255,0.2)', borderRadius: 14, padding: '16px 20px', transition: 'all 0.5s ease' }}>
                <div style={{ fontSize: '0.62rem', fontWeight: 700, letterSpacing: '0.18em', textTransform: 'uppercase', color: 'rgba(255,255,255,0.5)', marginBottom: 4 }}>Step {PHIL[activeIdx].n}</div>
                <div style={{ fontFamily: 'var(--serif)', fontSize: '1rem', fontWeight: 700, color: '#fff' }}>{PHIL[activeIdx].title}</div>
              </div>
            </div>

            {/* Right: step details */}
            <div style={{ display: 'flex', flexDirection: 'column', justifyContent: 'center' }}>
              <span style={{ fontSize: '0.68rem', fontWeight: 700, letterSpacing: '0.18em', textTransform: 'uppercase', color: 'var(--ink20)', display: 'block', marginBottom: 10 }}>Our Philosophy</span>
              <h2 style={{ fontFamily: 'var(--serif)', fontSize: 'clamp(1.8rem,4vw,2.8rem)', fontWeight: 900, color: 'var(--ink)', letterSpacing: '-0.025em', marginBottom: 36, lineHeight: 1.1 }}>
                How We Think <em style={{ fontStyle: 'italic', color: '#0057ff' }}>&amp; Build</em>
              </h2>

              {/* Step list */}
              <div style={{ display: 'flex', flexDirection: 'column', gap: 6, marginBottom: 36 }}>
                {PHIL.map(({ n, Icon, title }, i) => (
                  <div key={n} style={{
                    display: 'flex', alignItems: 'center', gap: 14,
                    padding: '12px 16px', borderRadius: 12,
                    background: activeIdx === i ? 'rgba(0,87,255,0.06)' : 'transparent',
                    border: activeIdx === i ? '1px solid rgba(0,87,255,0.18)' : '1px solid transparent',
                    transform: activeIdx === i ? 'translateX(10px)' : 'translateX(0)',
                    transition: 'all 0.45s cubic-bezier(0.16,1,0.3,1)',
                  }}>
                    <div style={{ width: 36, height: 36, borderRadius: 9, flexShrink: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', background: activeIdx === i ? '#0057ff' : 'var(--rule)', color: activeIdx === i ? '#fff' : 'var(--ink40)', transition: 'all 0.45s' }}>
                      <Icon size={15} />
                    </div>
                    <div>
                      <span style={{ fontSize: '0.6rem', fontWeight: 700, letterSpacing: '0.12em', textTransform: 'uppercase', color: activeIdx === i ? '#0057ff' : 'var(--ink20)', display: 'block' }}>Step {n}</span>
                      <strong style={{ fontSize: '0.92rem', color: activeIdx === i ? 'var(--ink)' : 'var(--ink40)', fontWeight: 600, transition: 'color 0.35s' }}>{title}</strong>
                    </div>
                    {activeIdx === i && <div style={{ marginLeft: 'auto', width: 7, height: 7, borderRadius: '50%', background: '#0057ff' }} />}
                  </div>
                ))}
              </div>

              {/* Active description */}
              <div style={{ background: 'var(--surf)', border: '1px solid var(--rule)', borderRadius: 16, padding: '24px 26px', transition: 'all 0.4s ease' }}>
                <p style={{ fontSize: '0.97rem', color: 'var(--ink60)', lineHeight: 1.9 }}>{PHIL[activeIdx].body}</p>
                {/* Progress dots */}
                <div style={{ display: 'flex', gap: 6, marginTop: 20 }}>
                  {PHIL.map((_, pi) => (
                    <div key={pi} style={{ height: 4, borderRadius: 2, transition: 'all 0.4s cubic-bezier(0.16,1,0.3,1)', background: pi === activeIdx ? '#0057ff' : 'var(--rule)', width: pi === activeIdx ? 28 : 7 }} />
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

/* ══════════════════════════════════════════════
