══════════════════════════════════════════════ */
function TeamCta() {
  const ref = useRef(null);
  const [ty, setTy] = useState(0);
  useEffect(() => {
    const fn = () => {
      if (!ref.current) return;
      const r = ref.current.getBoundingClientRect();
      setTy((window.innerHeight - r.top) * 0.18);
    };
    window.addEventListener('scroll', fn, { passive: true });
    return () => window.removeEventListener('scroll', fn);
  }, []);

  return (
    <section ref={ref} style={{ position: 'relative', overflow: 'hidden', padding: '110px 0', background: '#060c18' }}>
      <img src="https://images.unsplash.com/photo-1600880292203-757bb62b4baf?w=1600&q=75" alt="" aria-hidden
        style={{ position: 'absolute', inset: 0, width: '100%', height: '130%', objectFit: 'cover', opacity: 0.09, transform: `translateY(${ty}px)`, willChange: 'transform', transition: 'none' }} />
      <div style={{ position: 'absolute', inset: 0, background: 'linear-gradient(135deg, rgba(6,12,24,0.97), rgba(0,35,100,0.72))' }} />
      {/* Glow */}
      <div style={{ position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%,-50%)', width: 600, height: 600, background: 'radial-gradient(circle, rgba(0,87,255,0.07) 0%, transparent 70%)', pointerEvents: 'none' }} />

      <div className="wrap" style={{ position: 'relative', zIndex: 1 }}>
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: 44 }}>
          <Reveal dir="left" style={{ maxWidth: 580 }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 20 }}>
              <Users size={16} style={{ color: 'rgba(255,255,255,0.4)' }} />
              <span style={{ fontSize: '0.68rem', fontWeight: 700, letterSpacing: '0.18em', textTransform: 'uppercase', color: 'rgba(255,255,255,0.4)' }}>Leadership</span>
            </div>
            <h2 style={{ fontFamily: 'var(--serif)', fontSize: 'clamp(2rem,5vw,3.5rem)', fontWeight: 900, color: '#fff', marginBottom: 16, letterSpacing: '-0.028em', lineHeight: 1.08 }}>
              The Team Behind<br /><em style={{ fontStyle: 'italic', color: '#5aa8ff' }}>Synnoviq</em>
            </h2>
            <p style={{ fontSize: '0.97rem', color: 'rgba(255,255,255,0.5)', lineHeight: 1.85 }}>
              Deep technical expertise combined with strategic business thinking — hands-on engineers who set the standard for quality on every engagement.
            </p>
          </Reveal>
          <Reveal dir="right">
            <Link to="/team" style={{ display: 'inline-flex', alignItems: 'center', gap: 10, padding: '16px 34px', borderRadius: 14, background: '#fff', color: '#040b18', fontSize: '0.95rem', fontWeight: 800, boxShadow: '0 4px 24px rgba(255,255,255,0.1)', transition: 'all 0.25s ease' }}
              onMouseEnter={e => { e.currentTarget.style.background = '#0057ff'; e.currentTarget.style.color = '#fff'; e.currentTarget.style.transform = 'translateY(-3px)'; e.currentTarget.style.boxShadow = '0 12px 32px rgba(0,87,255,0.5)'; }}
              onMouseLeave={e => { e.currentTarget.style.background = '#fff'; e.currentTarget.style.color = '#040b18'; e.currentTarget.style.transform = ''; e.currentTarget.style.boxShadow = '0 4px 24px rgba(255,255,255,0.1)'; }}
            >Meet the Team <ArrowRight size={17} /></Link>
          </Reveal>
        </div>
      </div>
    </section>
  );
